import React, { useContext, useRef } from "react";
import RecommendedMoviesContext from "../../context/context";
import BookmarkMovie from "./BookmarkMovie";

const Bookmarks = () => {
    const ctx = useContext(RecommendedMoviesContext);
    const bookmarksElement = useRef();
    const bookmarkedMovies = () => {
        return ctx.bookmarkedMovies.map((movie) => {
            <BookmarkMovie movie={movie} />;
        });
    };
    const setRef = () => {
        ctx.setBookmarksRef(bookmarksElement);
    };
    return (
        <section class="bookmarksContainer">
            <div
                id="bookmarks"
                ref={ctx.bookmarksRef}
                ref={bookmarksElement}
                class="bookmarksHidden"
            >
                <h4 class="bookmarkTitle">Bookmarks</h4>
                <ul onLoad={setRef} id="bookmarksList">
                    {bookmarkedMovies()}
                </ul>
                {ctx.bookmarkedMovies == 0 ? (
                    <h3 class="emptyBookmark">You have no bookmark</h3>
                ) : (
                    ""
                )}
                <div class="Line"></div>
            </div>
        </section>
    );
};

export default Bookmarks;
